module reset_controller (  
    input clk,  
    input rst_n,  
    output reg out  
);  
    reg [3:0] ERR_count;  
    parameter DURATION = 10; // Duration for which output should be held low  

    always @(posedge clk or negedge rst_n) begin  
        if (!rst_n) begin  
            out <= 1'b0;  
            ERR_count <= 4'b0;  
        end else if (ERR_count < DURATION) begin  
            ERR_count <= ERR_count + 1;  
            out <= 1'b0;  
        end else begin  
            out <= 1'b1;  
        end  
    end  
endmodule
